      ".zhino-root[data-v-59292b97]{--zn-bg:#050810;--zn-primary:#a78bfa;--zn-primary-dim:rgba(167,139,250,0.15);--zn-text:rgba(255,255,255,0.88);--zn-text-dim:rgba(255,255,255,0.4);--zn-border:rgba(167,139,250,0.15);position:relative;font-family:'Segoe UI',system-ui,-apple-system,sans-serif;line-height:1.5}.zhino-root.zhino-warm[data-v-59292b97]{--zn-bg:#0d0806;--zn-primary:#f5a623;--zn-primary-dim:rgba(245,166,35,0.15);--zn-text:rgba(255,255,255,0.88);--zn-text-dim:rgba(255,255,255,0.4);--zn-border:rgba(245,166,35,0.15)}.zhino-fab[data-v-59292b97]{position:fixed;width:44px;height:44px;border-radius:50%;border:1px solid var(--zn-border);background:var(--zn-bg);cursor:grab;display:flex;align-items:center;justify-content:center;box-shadow:0 0 16px rgba(167,139,250,0.15),0 3px 14px rgba(0,0,0,0.4);color:var(--zn-primary);z-index:9999;-webkit-user-select:none;user-select:none;touch-action:none;padding:0;transition:box-shadow 0.2s,filter 0.15s}.zhino-fab[data-v-59292b97]:hover{box-shadow:0 0 28px rgba(167,139,250,0.3),0 5px 24px rgba(0,0,0,0.5);filter:brightness(1.15)}.zhino-fab[data-v-59292b97]:active,.zhino-fab.is-dragging[data-v-59292b97]{cursor:grabbing;filter:brightness(1)}.zhino-panel[data-v-59292b97]{position:fixed;border-radius:12px;border:1px solid var(--zn-border);background:var(--zn-bg);box-shadow:0 0 30px rgba(167,139,250,0.08),0 10px 40px rgba(0,0,0,0.5);display:flex;flex-direction:column;overflow:hidden;z-index:9999;color:var(--zn-text)}.zhino-panel.mobile[data-v-59292b97]{border-radius:16px 16px 0 0;border:none;border-top:1px solid var(--zn-border);box-shadow:0 -4px 24px rgba(0,0,0,0.3)}.zhino-panel-top[data-v-59292b97]{display:flex;align-items:center;padding:8px 12px;border-bottom:1px solid var(--zn-border);background:rgba(5,8,16,0.8);gap:8px;cursor:grab;-webkit-user-select:none;user-select:none;touch-action:none;flex-shrink:0}.mobile .zhino-panel-top[data-v-59292b97]{cursor:default;padding:12px 14px}.zhino-panel-top.dragging[data-v-59292b97]{cursor:grabbing}.zhino-panel-title[data-v-59292b97]{font-size:13px;font-weight:600;white-space:nowrap;color:var(--zn-primary)}.zhino-panel-model[data-v-59292b97]{font-size:11px;color:var(--zn-text-dim);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1}.zhino-btn-icon[data-v-59292b97]{width:28px;height:28px;border-radius:6px;border:none;background:transparent;color:var(--zn-text-dim);display:flex;align-items:center;justify-content:center;cursor:pointer;flex-shrink:0;transition:all 0.15s}.zhino-btn-icon[data-v-59292b97]:hover{background:var(--zn-primary-dim);color:var(--zn-primary)}.zhino-tab-switch[data-v-59292b97]{display:flex;gap:0;flex-shrink:0;border-bottom:1px solid var(--zn-border);background:rgba(5,8,16,0.6)}.zhino-tab-btn[data-v-59292b97]{flex:1;padding:7px 0;font-size:12px;font-weight:600;color:var(--zn-text-dim);background:transparent;border:none;border-bottom:2px solid transparent;cursor:pointer;transition:all 0.15s;text-align:center}.zhino-tab-btn[data-v-59292b97]:hover{color:var(--zn-text);background:rgba(167,139,250,0.04)}.zhino-tab-btn.active[data-v-59292b97]{color:var(--zn-primary);border-bottom-color:var(--zn-primary);background:var(--zn-primary-dim)}.mobile .zhino-tab-btn[data-v-59292b97]{padding:10px 0;font-size:13px}.zhino-panel-content[data-v-59292b97]{flex:1;min-height:0;overflow:hidden;padding:12px;display:flex;flex-direction:column}.zhino-resize-handle[data-v-59292b97]{position:absolute;right:0;bottom:0;width:16px;height:16px;cursor:nwse-resize;z-index:5}.zhino-resize-handle[data-v-59292b97]::after{content:'';position:absolute;right:3px;bottom:3px;width:8px;height:8px;border-right:2px solid rgba(167,139,250,0.25);border-bottom:2px solid rgba(167,139,250,0.25)}.zhino-resize-handle[data-v-59292b97]:hover::after{border-color:rgba(167,139,250,0.5)}.zhino-swipe-hint[data-v-59292b97]{display:flex;justify-content:center;padding:6px 0 2px;cursor:pointer;flex-shrink:0;background:rgba(5,8,16,0.8);touch-action:none}.zhino-swipe-bar[data-v-59292b97]{width:36px;height:4px;border-radius:2px;background:rgba(255,255,255,0.2)}.zhino-swipe-hint:active .zhino-swipe-bar[data-v-59292b97]{background:rgba(167,139,250,0.5)}.zhino-mobile-close-bar[data-v-59292b97]{flex-shrink:0;padding:8px 12px;padding-bottom:max(12px,env(safe-area-inset-bottom,12px));border-top:1px solid var(--zn-border);background:rgba(5,8,16,0.9);display:flex;justify-content:center}.zhino-mobile-close-btn[data-v-59292b97]{display:inline-flex;align-items:center;gap:6px;padding:8px 24px;border-radius:8px;border:1px solid rgba(167,139,250,0.2);background:rgba(167,139,250,0.06);color:var(--zn-primary);font-size:13px;font-weight:500;cursor:pointer;width:100%;justify-content:center}.zhino-mobile-close-btn[data-v-59292b97]:hover,.zhino-mobile-close-btn[data-v-59292b97]:active{background:rgba(167,139,250,0.15);border-color:rgba(167,139,250,0.4)}.zhino-fab-enter-active[data-v-59292b97],.zhino-fab-leave-active[data-v-59292b97]{transition:opacity 0.2s ease}.zhino-fab-enter-from[data-v-59292b97],.zhino-fab-leave-to[data-v-59292b97]{opacity:0}.zhino-panel-enter-active[data-v-59292b97],.zhino-panel-leave-active[data-v-59292b97]{transition:all 0.25s ease}.zhino-panel-enter-from[data-v-59292b97]{opacity:0}.zhino-panel-leave-to[data-v-59292b97]{opacity:0}.mobile.zhino-panel-enter-from[data-v-59292b97]{opacity:0}.mobile.zhino-panel-leave-to[data-v-59292b97]{opacity:0}.zhino-retry-toast[data-v-59292b97]{position:fixed;top:12px;right:12px;z-index:99999;max-width:360px;background:#1a1a2e;border:1px solid rgba(251,191,36,0.3);border-radius:8px;box-shadow:0 4px 16px rgba(0,0,0,0.4);padding:10px 14px;display:flex;gap:10px;align-items:flex-start;pointer-events:auto}.zhino-retry-toast-icon[data-v-59292b97]{font-size:16px;flex-shrink:0;margin-top:1px}.zhino-retry-toast-body[data-v-59292b97]{flex:1;min-width:0}.zhino-retry-toast-title[data-v-59292b97]{font-size:13px;font-weight:600;color:rgba(251,191,36,0.9)}.zhino-retry-toast-error[data-v-59292b97]{font-size:11px;color:rgba(248,113,113,0.75);margin-top:4px;font-family:monospace;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.zhino-retry-enter-active[data-v-59292b97]{transition:opacity 0.2s ease,transform 0.2s ease}.zhino-retry-leave-active[data-v-59292b97]{transition:opacity 0.15s ease}.zhino-retry-enter-from[data-v-59292b97]{opacity:0;transform:translateX(20px)}.zhino-retry-leave-to[data-v-59292b97]{opacity:0}\n",
